const qdrantUrl = 'http://host.docker.internal:6333'; // Update this to your instance endpoint
const collectionName = 'testing'; // Put your actual collection name here

// Using n8n's native context helper for direct REST interaction
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: `${qdrantUrl}/collections/${collectionName}/points/scroll`,
  headers: {
    'Content-Type': 'application/json',
    // 'api-key': 'YOUR_KEY' // Uncomment this specific line if you are using Qdrant Cloud
  },
  body: JSON.stringify({
    limit: 10,
    with_payload: false,
    with_vector: ["sparse-text"]
  }),
  json: true // Forces the helper to automatically parse the return payload as JSON
});

// Extract points and format them safely into an n8n-compliant iterable array
const points = response.result?.points || [];

return points.map(point => ({ json: point }));
